BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name ?text WHERE {
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name . }

  OPTIONAL {
    ?elem vocab:body ?textRaw .
    BIND(STR(?textRaw) AS ?text)
  }
  OPTIONAL {
    ?elem vocab:body ?textRaw2 .
    BIND(STR(?textRaw2) AS ?text)
  }
  FILTER(
    (BOUND(?text) && (
      CONTAINS(LCASE(?text), "purpose") ||
      CONTAINS(LCASE(?text), "main purpose") ||
      CONTAINS(LCASE(?text), "intent") ||
      CONTAINS(LCASE(?text), "objective") ||
      CONTAINS(LCASE(?text), "overview")
    ))
  )
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?purpose ?type ?name ?text WHERE {
  ?purpose rdf:type ?type ;
           vocab:NamedElement_name ?name .

  FILTER( LCASE(STR(?name)) = "purpose" )

  OPTIONAL { ?purpose vocab:body ?textRaw . BIND(STR(?textRaw) AS ?text) }
  OPTIONAL { ?purpose vocab:value ?textRaw2 . BIND(STR(?textRaw2) AS ?text) }
  OPTIONAL { ?purpose vocab:body ?textRaw3 . BIND(STR(?textRaw3) AS ?text) }

  FILTER(BOUND(?text) && STRLEN(?text) > 0)
}
ORDER BY ?name
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?purpose ?type ?name ?commentText WHERE {
  ?purpose rdf:type ?type ;
           vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), "purpose"))

  OPTIONAL {
    ?c rdf:type vocab:comment ;
       vocab:body ?commentText ;
       vocab:annotatedElement ?purpose .
  }

  OPTIONAL {
    ?purpose vocab:ownedComment ?c2 .
    ?c2 rdf:type vocab:comment ;
        vocab:body ?commentText2 .
  }
  BIND(COALESCE(?commentText2, ?commentText) AS ?commentText)
  FILTER(BOUND(?commentText) && STRLEN(?commentText) > 0)
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?purpose ?type ?name ?purposeText WHERE {
  ?purpose rdf:type ?type ;
           vocab:NamedElement_name ?name .

  FILTER(CONTAINS(LCASE(STR(?name)), "purpose"))

  OPTIONAL {
    ?c rdf:type vocab:comment ;
       vocab:body ?purposeText1 ;
       vocab:annotatedElement ?purpose .
  }

  OPTIONAL {
    ?purpose vocab:ownedComment ?c2 .
    ?c2 rdf:type vocab:comment ;
        vocab:body ?purposeText2 .
  }

  BIND(COALESCE(?purposeText2, ?purposeText1) AS ?purposeText)

  FILTER(BOUND(?purposeText) && STRLEN(?purposeText) > 0)
}
LIMIT 25
